SELECT Loops.AreaCode, Loops.LoopSymb, Loops.LoopNo, [Loops]![AreaCode] & [Loops]![LoopSymb] & [Loops]![LoopNo] AS Tag, IIf([Loops]![Deleted]=0,Null,IIf([Loops]![Deleted]=-1,"Yes","")) AS Deleted, [Loops]![Descr] AS Name, Loops.Notes, Loops.[Control Place], Loops.PIDwgNo, Loops.AI, Loops.AO, Loops.DI, Loops.DO, Loops.BUS, IIf([Loops]![Local]=0,"",IIf([Loops]![Local]=-1,"x")) AS [Local], IIf([Loops]![Software]=0,"",IIf([Loops]![Software]=-1,"x")) AS Software, "" AS RangeMin, "" AS RangeMax, "" AS RangeUnit, IIf([L] Is Not Null,[L] & " " & [AlarmUnit],"") AS AlarmL1, IIf([LL] Is Not Null,[LL] & " " & [AlarmUnit],"") AS AlarmL2, IIf([H] Is Not Null,[H] & " " & [AlarmUnit],"") AS AlarmH1, IIf([HH] Is Not Null,[HH] & " " & [AlarmUnit],"") AS AlarmH2, "" AS InterlockL1, "" AS InterlockL2, "" AS InterlockL3, "" AS InterlockL4, "" AS InterlockH1, "" AS InterlockH2, "" AS InterlockH3, "" AS InterlockH4, "" AS SafetyL1, "" AS SafetyL2, "" AS SafetyL3, "" AS SafetyH1, "" AS SafetyH2, "" AS SafetyH3, Loops.Rev, Loops.LoopOLD, Loops.InternalNote
FROM Loops
WHERE (((Loops.AreaCode) Like "SO*") AND ((Loops.InternalNote) Is Null))
ORDER BY Loops.AreaCode, Loops.LoopSymb, Loops.LoopNo;
